-- Migration 0030: Rewrite sofa seatHeightPrices to canonical 5-tier JSON.
--
-- Context
-- --------
-- Production Sheet v10 (2026-04-23) is the authoritative source for sofa
-- base + per-seat-height pricing. 0028 set these once, but at least one
-- record (5530-2A(LHF)) accumulated a malformed duplicate entry
-- {"height":"28","priceSen":0}  alongside the correct {"height":28,...}
-- so the UI occasionally read the zero row and showed a sofa as free.
--
-- This migration rewrites basePriceSen + seatHeightPrices on every sofa
-- SKU present in the v10 SKU SF sheet to a clean 5-entry JSON array with
-- integer height keys (24 / 28 / 30 / 32 / 35 cm). 61 of the 62 SKUs
-- already have these exact values so the UPDATE is a no-op; the one that
-- had the duplicate gets replaced with the clean canonical JSON.
--
-- Idempotent — safe to re-apply. Non-destructive to the 2 pillow SKUs
-- (LONG PILLOW / SQUARE PILLOW) that aren't in the SKU SF sheet.

UPDATE products SET basePriceSen = 51700, seatHeightPrices = '[{"height":24,"priceSen":51700},{"height":28,"priceSen":57200},{"height":30,"priceSen":57200},{"height":32,"priceSen":77200},{"height":35,"priceSen":77200}]' WHERE code = '5530-1NA' AND category = 'SOFA';
